    z = "[[" + "]\n[".join(" ".join(map(str, row)) for row in M.rows()) + "]]"
    ret = check_output(["flatter"], input=z.encode())
    return matrix(M.nrows(), M.ncols(), map(int, findall(b"-?\\d+", ret)))


